#!/usr/bin/env python3

"""
Test case that could be added to the Redshift test suite to validate the fix.
"""

from tests.dialects.test_dialect import Validator

class TestRedshiftFloatPrecision(Validator):
    dialect = "redshift"

    def test_float_precision_stripping(self):
        """Test that Redshift strips precision from floating-point types."""

        # FLOAT(8) should become DOUBLE PRECISION (without precision)
        self.validate_all(
            "SELECT CAST(a AS FLOAT(8))",
            write={
                "postgres": "SELECT CAST(a AS DOUBLE PRECISION(8))",
                "redshift": "SELECT CAST(a AS DOUBLE PRECISION)",
            },
        )

        # FLOAT(4) should become REAL (but FLOAT with precision still gets stripped) 
        self.validate_all(
            "SELECT CAST(a AS FLOAT(4))",
            write={
                "postgres": "SELECT CAST(a AS DOUBLE PRECISION)",  # Gets normalized to DOUBLE
                "redshift": "SELECT CAST(a AS DOUBLE PRECISION)",  # Precision stripped
            },
        )

        # Explicit DOUBLE PRECISION with precision should be stripped
        self.validate_all(
            "SELECT CAST(a AS DOUBLE PRECISION(15))",
            write={
                "postgres": "SELECT CAST(a AS DOUBLE PRECISION(15))",
                "redshift": "SELECT CAST(a AS DOUBLE PRECISION)",
            },
        )

        # REAL without precision should remain unchanged
        self.validate_all(
            "SELECT CAST(a AS REAL)",
            write={
                "postgres": "SELECT CAST(a AS REAL)",
                "redshift": "SELECT CAST(a AS REAL)",
            },
        )

if __name__ == "__main__":
    test_instance = TestRedshiftFloatPrecision()
    test_instance.test_float_precision_stripping()
    print("✅ All Redshift float precision tests passed!")

